package service; import repository.*; import model.*; import strategy.*; import java.util.*; public class BookService{ private final BookRepository repo; public BookService(BookRepository r){repo=r;} public void add(Book b){repo.save(b);} public void remove(String isbn){repo.delete(isbn);} public List<Book> search(SearchStrategy s, String k){return s.search(repo.findAll(),k);} public Collection<Book> getAll(){return repo.findAll();}}